var shocknetGlobal = "/*\n * ═══════════════════════════════════════════════════════════════════════════\n *  SHOCKNET — Design System  ·  Global Stylesheet\n *  shocknet-global.css  ·  v1.2\n * ═══════════════════════════════════════════════════════════════════════════\n *\n *  This file defines every rule shared across ALL SHOCKNET products.\n *  Import it once, before any product-specific stylesheet.\n *\n *  LOAD ORDER\n *  ─────────────────────────────────────────────────────────────────────────\n *  1. shocknet-global.css          ← this file (always required)\n *  2. shocknet-[product].css       ← one per product (optional per page)\n *\n *  THEME SWITCHING\n *  ─────────────────────────────────────────────────────────────────────────\n *  Default: dark.\n *  Switch:  document.documentElement.setAttribute('data-theme', 'light')\n *           document.documentElement.setAttribute('data-theme', 'dark')\n *\n *  TYPEFACES  — load BEFORE this file\n *  ─────────────────────────────────────────────────────────────────────────\n *  DM Mono   weights 300 · 400 · 500   fonts.google.com/specimen/DM+Mono\n *  Inter     weights 400 · 500 · 600   rsms.me/inter\n *\n *  CDN snippet (development — self-host in production for GDPR compliance):\n *  <link href=\"https://fonts.googleapis.com/css2?family=DM+Mono:ital,wght@0,300;0,400;0,500;1,300;1,400&family=Inter:wght@400;500;600&display=swap\" rel=\"stylesheet\">\n *\n * ═══════════════════════════════════════════════════════════════════════════\n *  TABLE OF CONTENTS\n *  ─────────────────────────────────────────────────────────────────────────\n *  01  Core Color Tokens          :root · dark theme defaults\n *  02  Light Theme Override       [data-theme=\"light\"]\n *  03  Typography Tokens          font stacks, sizes, weights, spacing\n *  04  Spacing Scale              4 px base unit\n *  05  Border Radius\n *  06  Transitions\n *  07  Elevation & Glow\n *  08  Grid & Layout\n *  09  Global Reset & Base\n *  10  Typography Elements        h1–h6, p, code, .section-tag, .rule, hr\n *  11  Surfaces                   .card, .card-sm, .card-inset, .demo-box\n *  12  Navigation                 .nav, .nav-links, .nav-link, .toggle-btn\n *  13  Buttons — Base             .btn, .btn-sm, ghost variants\n *  14  Buttons — SHOCKNET\n *  15  Pills                      .pill + neutral variants\n *  16  Download Row               .dl-row, .dl-btn\n *  17  Spec Row                   .spec-row\n *  18  Callout                    .callout\n *  19  Logo Box & Mark Pair       .logo-box, .mark-pair, .mark-dark, .mark-light\n *  20  Color Swatches             .swatch, .swatch-split\n *  21  Chapter / Section Labels   .chapter, .section-tag, .product-bar\n *  22  Icon Cells                 .icon-cell, .icon-grid\n *  23  App Icons & Favicons       .app-icon, .fav-box\n *  24  Form Elements              input, textarea, select\n *  25  Theme Toggle               .toggle-wrap, .toggle-btn\n *  26  Do / Don't Grid            .do-dont-grid, .dont-cell\n *  27  Voice & Tone               .voice-pillars, .tone-matrix, .copy-example\n *  28  Co-branding                .cobranding-rule, .excl-zone\n *  29  SVG Helpers                .wm, .cover-grid\n *  30  Footer\n *  31  Utilities\n *  32  Responsive Breakpoints\n * ═══════════════════════════════════════════════════════════════════════════\n */\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  01  CORE COLOR TOKENS  —  :root  (dark theme is the default)\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n:root,\n[data-theme=\"dark\"] {\n\n  /* ── Background & Surface ──────────────────────────────────────────── */\n  --color-bg:         #111213;   /* Night    */\n  --color-surface:    #212325;   /* Coal     */\n  --color-surface-2:  #1A1B1C;\n  --color-surface-3:  #2C2E30;\n\n  /* ── Border ─────────────────────────────────────────────────────────── */\n  --color-border:     #3C3C3C;   /* Graphene */\n  --color-border-sub: #1E1E1E;\n\n  /* ── Text ───────────────────────────────────────────────────────────── */\n  --color-text:       #F1F1F1;   /* Ice      */\n  --color-text-muted: #8A8A8A;   /* Dust     */\n  --color-text-dim:   #505050;\n\n  /* ── Nav ─────────────────────────────────────────────────────────────── */\n  --color-nav-bg:     rgba(17, 18, 19, 0.92);\n  --color-nav-border: #3C3C3C;\n\n  /* ── Ghost elements ─────────────────────────────────────────────────── */\n  --color-ghost-border: #3C3C3C;\n  --color-ghost-text:   #F1F1F1;\n\n  /* ── Grid overlay ───────────────────────────────────────────────────── */\n  --color-grid-line:  rgba(255, 255, 255, 0.025);\n\n  /* ── SHOCKNET parent accent ─────────────────────────────────────────── */\n  --color-sn:         #F1F1F1;\n  --color-sn-on:      #111213;\n\n  /* ── Semantic status ────────────────────────────────────────────────── */\n  --color-danger:  #FF0050;\n  --color-success: #25E673;\n  --color-warning: #F7FF00;\n  --color-info:    #1BCFE0;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  02  LIGHT THEME OVERRIDE\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n[data-theme=\"light\"] {\n\n  --color-bg:         #F2F2EF;   /* Shell    */\n  --color-surface:    #FFFFFF;\n  --color-surface-2:  #F7F7F5;\n  --color-surface-3:  #EBEBEA;\n\n  --color-border:     #D0D0CC;\n  --color-border-sub: #E8E8E5;\n\n  --color-text:       #111213;\n  --color-text-muted: #555555;\n  --color-text-dim:   #999999;\n\n  --color-nav-bg:     rgba(242, 242, 239, 0.94);\n  --color-nav-border: #D0D0CC;\n\n  --color-ghost-border: #D0D0CC;\n  --color-ghost-text:   #111213;\n\n  --color-grid-line:  rgba(0, 0, 0, 0.04);\n\n  --color-sn:         #111213;\n  --color-sn-on:      #F2F2EF;\n\n  --color-danger:  #FF3366;\n  --color-success: #4FD27A;\n  --color-warning: #F0E91A;\n  --color-info:    #4FD6F0;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  03  TYPOGRAPHY TOKENS\n *\n *  Heading font: DM Mono\n *    H1–H3  weight 300 (Light)\n *    H4–H6  weight 400 (Regular)\n *\n *  Letter-spacing per level (exact values from brand manual):\n *    H1  −0.042em   H2  −0.021em   H3  −0.014em\n *    H4  −0.007em   H5  +0.007em   H6  +0.042em + ALLCAPS\n *\n *  Body / buttons: Inter\n *  Labels / mono:  DM Mono\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n:root {\n  /* ── Font Families ───────────────────────────────────────────────────── */\n  --font-display: 'DM Mono', 'Courier New', monospace;\n  --font-body:    'Inter', system-ui, -apple-system, sans-serif;\n  --font-mono:    'DM Mono', 'Liberation Mono', 'Courier New', monospace;\n\n  /* ── Font Sizes ──────────────────────────────────────────────────────── */\n  --text-h1:    42px;\n  --text-h2:    36px;\n  --text-h3:    24px;\n  --text-h4:    21px;\n  --text-h5:    18px;\n  --text-h6:    16px;\n  --text-base:  16px;   /* Body copy, button labels                       */\n  --text-sm:    14px;   /* Small body, captions                           */\n  --text-xs:    12px;   /* Mono support / technical                       */\n  --text-label: 10px;   /* Pill labels, nav links, section tags           */\n  --text-micro:  8px;   /* Annotations, badges                            */\n\n  /* ── Font Weights ────────────────────────────────────────────────────── */\n  --weight-light:    300;   /* DM Mono — H1, H2, H3                       */\n  --weight-regular:  400;   /* DM Mono — H4, H5, H6 · Inter body          */\n  --weight-medium:   500;   /* Inter — buttons, emphasis                  */\n  --weight-semibold: 600;   /* Inter — strong emphasis (use sparingly)    */\n\n  /* ── Letter Spacing — Headings (exact per level, do not override) ────── */\n  --tracking-h1: -0.042em;\n  --tracking-h2: -0.021em;\n  --tracking-h3: -0.014em;\n  --tracking-h4: -0.007em;\n  --tracking-h5:  0.007em;\n  --tracking-h6:  0.042em;  /* H6 also uses text-transform: uppercase     */\n\n  /* ── Letter Spacing — Interface ─────────────────────────────────────── */\n  --tracking-label: 0.15em;   /* Nav links, section tags, pills           */\n  --tracking-mono:  0.05em;   /* DM Mono body / technical                 */\n  --tracking-wide:  0.20em;   /* Section eyebrows                         */\n\n  /* ── Line Heights ────────────────────────────────────────────────────── */\n  --leading-display: 1.10;\n  --leading-heading: 1.15;\n  --leading-body:    1.75;\n  --leading-tight:   1.30;\n  --leading-mono:    1.60;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  04  SPACING SCALE  (4 px base unit — all values are multiples of 4)\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n:root {\n  --space-1:   4px;\n  --space-2:   8px;\n  --space-3:  12px;\n  --space-4:  16px;\n  --space-5:  24px;\n  --space-6:  32px;\n  --space-7:  48px;\n  --space-8:  64px;\n  --space-9:  96px;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  05  BORDER RADIUS\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n:root {\n  --radius-sm:   5px;\n  --radius-md:  10px;\n  --radius-lg:  16px;\n  --radius-xl:  24px;\n  --radius-full: 9999px;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  06  TRANSITIONS\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n:root {\n  --transition-fast:   .15s ease;\n  --transition-base:   .25s ease;\n  --transition-slow:   .40s ease;\n  --transition-theme:  .35s ease;\n  --transition-spring: .40s cubic-bezier(.34, 1.56, .64, 1);\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  07  ELEVATION & GLOW\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n:root {\n  --shadow-sm:  0 1px  3px rgba(0,0,0,.35), 0 1px 2px rgba(0,0,0,.20);\n  --shadow-md:  0 4px 12px rgba(0,0,0,.40), 0 2px 6px rgba(0,0,0,.25);\n  --shadow-lg:  0 12px 32px rgba(0,0,0,.50), 0 4px 12px rgba(0,0,0,.30);\n\n  /* Product glow — used on button hover, active pill, focus ring */\n  --glow-sn: 0 0 16px rgba(241,241,241,.18);\n  --glow-sw: 0 0 20px rgba(27,207,224,.22);\n  --glow-lp: 0 0 20px rgba(255,138,0,.22);\n  --glow-lv: 0 0 20px rgba(255,0,80,.22);\n  --glow-cl: 0 0 20px rgba(247,255,0,.18);\n  --glow-sa: 0 0 20px rgba(37,230,115,.20);\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  08  GRID & LAYOUT\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n:root {\n  --grid-columns: 12;\n  --grid-gutter:  20px;\n  --grid-max-w:   1200px;\n  --page-pad:      48px;\n  --page-pad-md:   24px;\n  --page-pad-sm:   16px;\n}\n\n.page {\n  max-width: var(--grid-max-w);\n  margin-inline: auto;\n  padding-inline: var(--page-pad);\n}\n\n.g2 { display: grid; grid-template-columns: 1fr 1fr;       gap: 20px; }\n.g3 { display: grid; grid-template-columns: 1fr 1fr 1fr;   gap: 18px; }\n.g4 { display: grid; grid-template-columns: 1fr 1fr 1fr 1fr; gap: 14px; }\n\n.grid-12 { display: grid; grid-template-columns: repeat(12, 1fr); gap: var(--grid-gutter); }\n.col-12  { grid-column: span 12; }\n.col-8   { grid-column: span  8; }\n.col-6   { grid-column: span  6; }\n.col-4   { grid-column: span  4; }\n.col-3   { grid-column: span  3; }\n\n.row { display: flex; align-items: center; gap: 12px; flex-wrap: wrap; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  09  GLOBAL RESET & BASE\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n*,\n*::before,\n*::after { box-sizing: border-box; margin: 0; padding: 0; }\n\nhtml { scroll-behavior: smooth; -webkit-text-size-adjust: 100%; }\n\nbody {\n  background-color: var(--color-bg);\n  color:            var(--color-text);\n  font-family:      var(--font-body);\n  font-size:        var(--text-base);\n  line-height:      var(--leading-body);\n  -webkit-font-smoothing:  antialiased;\n  -moz-osx-font-smoothing: grayscale;\n  transition:\n    background-color var(--transition-theme),\n    color            var(--transition-theme);\n}\n\nimg, svg { display: block; max-width: 100%; }\n\na {\n  color: var(--color-text-dim);\n  text-decoration: none;\n  transition: color var(--transition-fast);\n}\na:hover { color: var(--color-text); }\n\nsection {\n  padding: var(--space-9) 0;\n  border-bottom: 1px dashed var(--color-border);\n  transition: border-color var(--transition-base);\n}\nsection:last-child { border-bottom: none; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  10  TYPOGRAPHY ELEMENTS\n *\n *  Heading font:  DM Mono\n *  ─── H1–H3  weight 300, letter-spacing as defined per level\n *  ─── H4–H6  weight 400, letter-spacing as defined per level\n *  ─── H6     also text-transform: uppercase\n *\n *  Body:   Inter 400  16px  line-height 1.75\n *  Mono:   DM Mono 400  12px  tracking 0.05em\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n/* ── Heading base ─────────────────────────────────────────────────────────── */\nh1, h2, h3, h4, h5, h6,\n.h1, .h2, .h3, .h4, .h5, .h6 {\n  font-family: var(--font-display);\n  line-height:  var(--leading-heading);\n  color:        var(--color-text);\n  transition:   color var(--transition-theme);\n}\n\n/* H1–H3: Light (300) — tight to negative tracking */\nh1, .h1 {\n  font-size:      var(--text-h1);          /* 42px */\n  font-weight:    var(--weight-light);     /* 300  */\n  letter-spacing: var(--tracking-h1);      /* -.042em */\n}\n\nh2, .h2 {\n  font-size:      var(--text-h2);          /* 36px */\n  font-weight:    var(--weight-light);     /* 300  */\n  letter-spacing: var(--tracking-h2);      /* -.021em */\n}\n\nh3, .h3 {\n  font-size:      var(--text-h3);          /* 24px */\n  font-weight:    var(--weight-light);     /* 300  */\n  letter-spacing: var(--tracking-h3);      /* -.014em */\n}\n\n/* H4–H6: Regular (400) — neutral to open tracking */\nh4, .h4 {\n  font-size:      var(--text-h4);          /* 21px */\n  font-weight:    var(--weight-regular);   /* 400  */\n  letter-spacing: var(--tracking-h4);      /* -.007em */\n}\n\nh5, .h5 {\n  font-size:      var(--text-h5);          /* 18px */\n  font-weight:    var(--weight-regular);   /* 400  */\n  letter-spacing: var(--tracking-h5);      /* +.007em */\n}\n\nh6, .h6 {\n  font-size:      var(--text-h6);          /* 16px */\n  font-weight:    var(--weight-regular);   /* 400  */\n  letter-spacing: var(--tracking-h6);      /* +.042em */\n  text-transform: uppercase;\n}\n\n/* ── Body text ────────────────────────────────────────────────────────────── */\np, .body {\n  font-family: var(--font-body);\n  font-size:   var(--text-base);\n  font-weight: var(--weight-regular);\n  line-height: var(--leading-body);\n  color:       var(--color-text-muted);\n  transition:  color var(--transition-theme);\n}\n\n.body-sm {\n  font-size:   var(--text-sm);\n  line-height: var(--leading-tight);\n}\n\n/* ── Monospace / technical ───────────────────────────────────────────────── */\ncode,\n.mono {\n  font-family:    var(--font-mono);\n  font-size:      var(--text-xs);          /* 12px */\n  font-weight:    var(--weight-regular);\n  letter-spacing: var(--tracking-mono);    /* .05em */\n  color:          var(--color-text-dim);\n  transition:     color var(--transition-theme);\n}\n\n/* ── Section tag / eyebrow (DM Mono, 10px, allcaps, wide tracking) ────────── */\n.section-tag {\n  display:        block;\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);       /* 10px */\n  font-weight:    var(--weight-regular);\n  letter-spacing: var(--tracking-wide);    /* .20em */\n  text-transform: uppercase;\n  color:          var(--color-text-dim);\n  margin-bottom:  10px;\n  transition:     color var(--transition-theme);\n}\n\n/* ── Chapter number ─────────────────────────────────────────────────────── */\n.ch-num {\n  font-family:    var(--font-mono);\n  font-size:      var(--text-xs);          /* 12px */\n  color:          var(--color-text-dim);\n  letter-spacing: var(--tracking-wide);\n  flex-shrink:    0;\n  padding-top:    4px;\n  transition:     color var(--transition-theme);\n}\n\n.chapter {\n  display:       flex;\n  align-items:   baseline;\n  gap:           20px;\n  margin-bottom: 16px;\n}\n\n/* ── Rule / separator ───────────────────────────────────────────────────── */\n.rule {\n  width:      40px;\n  height:     1px;\n  background: var(--color-border);\n  margin:     24px 0;\n  border:     none;\n  transition: background var(--transition-theme);\n}\n.rule-wide { width: 80px; }\n\nhr {\n  border:     none;\n  height:     1px;\n  background: var(--color-border);\n  margin:     var(--space-5) 0;\n  transition: background var(--transition-theme);\n}\n\n/* ── Type specimens (brand manual only) ─────────────────────────────────── */\n.type-s {\n  background:    var(--color-surface);\n  border:        1px solid var(--color-border);\n  border-radius: var(--radius-md);\n  padding:       24px 28px;\n  margin-bottom: 2px;\n  transition:\n    background var(--transition-theme),\n    border-color var(--transition-theme);\n}\n.type-s .meta {\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);\n  color:          var(--color-text-dim);\n  margin-bottom:  12px;\n  display:        block;\n  letter-spacing: var(--tracking-mono);\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  11  SURFACES\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.card {\n  background:    var(--color-surface);\n  border:        1px solid var(--color-border);\n  border-radius: var(--radius-md);   /* 10px */\n  padding:       var(--space-6);     /* 32px */\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n\n.card-sm {\n  background:    var(--color-surface);\n  border:        1px solid var(--color-border);\n  border-radius: var(--radius-md);\n  padding:       var(--space-4);     /* 16px */\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n\n.card-inset {\n  background:    var(--color-bg);\n  border:        1px solid var(--color-border-sub);\n  border-radius: var(--radius-md);\n  padding:       var(--space-5);\n}\n\n.demo-box {\n  background:    var(--color-surface);\n  border:        1px solid var(--color-border);\n  border-radius: var(--radius-md);\n  padding:       36px;\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n\n/* Fixed dark/light panel pair (always locked regardless of theme toggle) */\n.panel-dark  {\n  background:    #111213;\n  border:        1px solid #3C3C3C;\n  border-radius: var(--radius-md);\n}\n.panel-light {\n  background:    #F2F2EF;\n  border:        1px solid #D0D0CC;\n  border-radius: var(--radius-md);\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  12  NAVIGATION\n * ═══════════════════════════════════════════════════════════════════════════ */\n\nnav {\n  position:          sticky;\n  top:               0;\n  z-index:           100;\n  background:        var(--color-nav-bg);\n  backdrop-filter:   blur(16px);\n  -webkit-backdrop-filter: blur(16px);\n  border-bottom:     1px solid var(--color-nav-border);\n  display:           flex;\n  align-items:       stretch;\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n\n.nav-links {\n  display:      flex;\n  list-style:   none;\n  overflow-x:   auto;\n  flex:         1;\n  min-width:    0;\n  scrollbar-width: none;\n}\n.nav-links::-webkit-scrollbar { display: none; }\n\n.nav-links li a,\n.nav-link {\n  display:        block;\n  padding:        16px;\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);    /* 10px */\n  letter-spacing: var(--tracking-label);/* .15em */\n  text-transform: uppercase;\n  color:          var(--color-text-dim);\n  text-decoration: none;\n  white-space:    nowrap;\n  transition:     color var(--transition-fast);\n}\n.nav-links li a:hover,\n.nav-link:hover { color: var(--color-text); }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  13  BUTTONS — BASE\n *\n *  Normal: h 42px · r 10px · Inter Medium 16px\n *  Small:  h 36px · r  5px · Inter Medium 12px\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.btn,\n.btn-sm {\n  display:         inline-flex;\n  align-items:     center;\n  justify-content: center;\n  gap:             var(--space-2);\n  cursor:          pointer;\n  border:          none;\n  white-space:     nowrap;\n  font-family:     var(--font-body);\n  font-weight:     var(--weight-medium);  /* Inter 500 */\n  text-decoration: none;\n  transition:\n    opacity       var(--transition-fast),\n    transform     var(--transition-fast),\n    background    var(--transition-base),\n    color         var(--transition-base),\n    border-color  var(--transition-base),\n    box-shadow    var(--transition-base);\n}\n\n/* Normal */\n.btn {\n  height:        42px;\n  padding:       0 24px;\n  border-radius: var(--radius-md);   /* 10px */\n  font-size:     var(--text-base);   /* 16px */\n}\n\n/* Small */\n.btn-sm {\n  height:        36px;\n  padding:       0 16px;\n  border-radius: var(--radius-sm);   /* 5px  */\n  font-size:     12px;\n}\n\n.btn:hover,\n.btn-sm:hover  { opacity: .88; }\n\n.btn:active,\n.btn-sm:active { transform: scale(.98); }\n\n.btn:disabled,\n.btn-sm:disabled {\n  opacity:        .30;\n  cursor:         not-allowed;\n  pointer-events: none;\n}\n\n/* Icons inside buttons */\n.btn    svg, .btn    ion-icon { font-size: 18px; flex-shrink: 0; }\n.btn-sm svg, .btn-sm ion-icon { font-size: 14px; flex-shrink: 0; }\n\n/* Ghost variants */\n.btn-ghost    { background: transparent; border: 1px solid var(--color-ghost-border); color: var(--color-ghost-text); }\n.btn-ghost-sm { background: transparent; border: 1px solid var(--color-ghost-border); color: var(--color-ghost-text); }\n.btn-ghost:hover,\n.btn-ghost-sm:hover { opacity: .88; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  14  BUTTONS — SHOCKNET (parent / monochrome)\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.btn-sn,\n.btn-sn-sm  { background: var(--color-sn); color: var(--color-sn-on); }\n.btn-sn:hover,\n.btn-sn-sm:hover { box-shadow: var(--glow-sn); }\n\n.btn-sn-out {\n  background:   transparent;\n  border:       1px solid var(--color-sn);\n  color:        var(--color-sn);\n}\n.btn-sn-out:hover { box-shadow: var(--glow-sn); }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  15  PILLS\n *\n *  Font: DM Mono 10px, tracking .10em–.15em, ALLCAPS\n *  All product-colored pill variants live in each product's CSS file.\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.pill {\n  display:        inline-flex;\n  align-items:    center;\n  gap:            5px;\n  padding:        3px 10px;\n  border-radius:  var(--radius-full);\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);    /* 10px */\n  font-weight:    var(--weight-regular);\n  letter-spacing: 0.10em;\n  text-transform: uppercase;\n  line-height:    1;\n  transition:\n    background   var(--transition-base),\n    border-color var(--transition-base),\n    color        var(--transition-base);\n}\n\n/* Neutral pills */\n.pill-aa  {\n  background: var(--color-bg);\n  border:     1px solid var(--color-border);\n  color:      var(--color-text);\n}\n.pill-def {\n  background: var(--color-surface);\n  border:     1px solid var(--color-border);\n  color:      var(--color-text-muted);\n}\n\n/* Dot indicator modifier */\n.pill--dot::before {\n  content:       '';\n  display:       inline-block;\n  width:         5px;\n  height:        5px;\n  border-radius: 50%;\n  background:    currentColor;\n  flex-shrink:   0;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  16  DOWNLOAD ROW\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.dl-row {\n  display:       flex;\n  gap:           10px;\n  flex-wrap:     wrap;\n  padding:       24px 0 0;\n  border-top:    1px solid color-mix(in srgb, var(--color-border) 60%, transparent);\n  margin-top:    24px;\n  transition:    border-color var(--transition-theme);\n}\n\n.dl-label {\n  width:          100%;\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);\n  letter-spacing: var(--tracking-mono);\n  text-transform: uppercase;\n  margin-bottom:  var(--space-2);\n  color:          var(--color-text-dim);\n  transition:     color var(--transition-theme);\n}\n\n.dl-btn {\n  display:        inline-flex;\n  align-items:    center;\n  gap:            8px;\n  height:         38px;\n  padding:        0 18px;\n  border-radius:  8px;\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);\n  letter-spacing: 0.10em;\n  text-transform: uppercase;\n  cursor:         pointer;\n  border:         1px solid var(--color-border);\n  background:     var(--color-surface);\n  color:          var(--color-text-muted);\n  text-decoration: none;\n  transition:\n    background   var(--transition-fast),\n    color        var(--transition-fast),\n    border-color var(--transition-fast);\n}\n.dl-btn:hover {\n  border-color: var(--color-text-muted);\n  color:        var(--color-text);\n}\n.dl-btn .dl-dot {\n  width:         8px;\n  height:        8px;\n  border-radius: 50%;\n  flex-shrink:   0;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  17  SPEC ROW  (definition / key–value pair)\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.spec-row {\n  display:         flex;\n  justify-content: space-between;\n  align-items:     center;\n  padding:         10px 0;\n  border-bottom:   1px solid color-mix(in srgb, var(--color-border) 50%, transparent);\n  transition:      border-color var(--transition-theme);\n}\n.spec-row:last-child { border-bottom: none; }\n\n.spec-k {\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);\n  color:          var(--color-text-dim);\n  text-transform: uppercase;\n  letter-spacing: 0.10em;\n}\n.spec-v {\n  font-family: var(--font-mono);\n  font-size:   var(--text-label);\n  color:       var(--color-text);\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  18  CALLOUT\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.callout {\n  display:       flex;\n  align-items:   flex-start;\n  gap:           14px;\n  padding:       18px 22px;\n  border-radius: var(--radius-md);\n  margin-bottom: 28px;\n  background:    color-mix(in srgb, var(--color-text) 5%,  transparent);\n  border:        1px solid color-mix(in srgb, var(--color-text) 15%, transparent);\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n\n.callout-icon {\n  font-size:   17px;\n  flex-shrink: 0;\n  margin-top:  2px;\n}\n\n.callout h6 { margin-bottom: 4px; font-size: 12px; letter-spacing: .04em; color: var(--color-text); }\n.callout p  { font-size: 13px; color: var(--color-text-muted); }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  19  LOGO BOX & MARK PAIR\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.logo-box {\n  background:      var(--color-surface);\n  border:          1px solid var(--color-border);\n  border-radius:   var(--radius-md);\n  padding:         48px 40px;\n  display:         flex;\n  align-items:     center;\n  justify-content: center;\n  min-height:      140px;\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n\n.mark-pair {\n  display:               grid;\n  grid-template-columns: 1fr 1fr;\n  gap:                   10px;\n}\n\n/* Fixed-background cells — always locked, independent of theme toggle */\n.mark-dark {\n  background:    #111213;\n  border:        1px solid #3C3C3C;\n  border-radius: var(--radius-md);\n  padding:       20px;\n  display:       flex;\n  justify-content: center;\n  align-items:   center;\n  min-height:    110px;\n}\n.mark-light {\n  background:    #F2F2EF;\n  border:        1px solid #D0D0CC;\n  border-radius: var(--radius-md);\n  padding:       20px;\n  display:       flex;\n  justify-content: center;\n  align-items:   center;\n  min-height:    110px;\n}\n\n.product-bar {\n  width:         4px;\n  height:        44px;\n  border-radius: 2px;\n  flex-shrink:   0;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  20  COLOR SWATCHES\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n/* Single swatch */\n.sw-grid {\n  display:               grid;\n  grid-template-columns: repeat(auto-fill, minmax(148px, 1fr));\n  gap:                   12px;\n}\n.swatch {\n  border-radius: 8px;\n  overflow:      hidden;\n  border:        1px solid var(--color-border);\n  transition:    border-color var(--transition-theme);\n}\n.swatch-c { height: 68px; }\n.swatch-i {\n  background: var(--color-surface);\n  padding:    10px 12px;\n  transition: background var(--transition-theme);\n}\n.swatch-i .nm { font-size: 11px; font-weight: 500; color: var(--color-text); margin-bottom: 2px; }\n.swatch-i .hx { font-family: var(--font-mono); font-size: 10px; color: var(--color-text-muted); }\n\n/* Split swatch (dark left / light right — always fixed) */\n.cmp-grid {\n  display:               grid;\n  grid-template-columns: repeat(auto-fill, minmax(222px, 1fr));\n  gap:                   12px;\n}\n.cmp-swatch {\n  border-radius: var(--radius-md);\n  overflow:      hidden;\n  border:        1px solid var(--color-border);\n  transition:    border-color var(--transition-theme);\n}\n.cmp-halves { display: flex; }\n.cmp-h { height: 56px; flex: 1; }\n.cmp-body {\n  background: var(--color-surface);\n  padding:    12px 14px;\n  transition: background var(--transition-theme);\n}\n.cmp-body .cn { font-size: 11px; font-weight: 500; color: var(--color-text); margin-bottom: 7px; }\n.cmp-row  { display: flex; align-items: center; gap: 7px; margin-bottom: 4px; }\n.cmp-dot  { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }\n.cmp-val  { font-family: var(--font-mono); font-size: 10px; color: var(--color-text-muted); flex: 1; }\n.cmp-tag  { font-family: var(--font-mono); font-size: 8px; text-transform: uppercase; letter-spacing: .08em; padding: 1px 5px; border-radius: 3px; }\n.tag-d    { background: rgba(255,255,255,.08); color: #888; }\n.tag-l    { background: rgba(0,0,0,.07);       color: #888; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  21  CHAPTER / SECTION LABELS\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.icon-section-header {\n  display:       flex;\n  align-items:   center;\n  gap:           10px;\n  margin-bottom: 20px;\n}\n.icon-section-header__bar {\n  width:         3px;\n  height:        20px;\n  border-radius: 2px;\n  flex-shrink:   0;\n}\n.icon-section-header__label {\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);\n  letter-spacing: var(--tracking-label);\n  text-transform: uppercase;\n  color:          var(--color-text-dim);\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  22  ICON CELLS & ICON GRID\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.icon-grid {\n  display:               grid;\n  grid-template-columns: repeat(auto-fill, minmax(72px, 1fr));\n  gap:                   4px;\n}\n\n.icon-cell {\n  display:         flex;\n  flex-direction:  column;\n  align-items:     center;\n  gap:             8px;\n  padding:         14px 6px;\n  border-radius:   8px;\n  transition:      background var(--transition-fast);\n  cursor:          default;\n}\n.icon-cell:hover { background: color-mix(in srgb, var(--color-text) 6%, transparent); }\n\n.icon-cell__glyph { font-size: 22px; }\n.icon-cell__label {\n  font-family:    var(--font-mono);\n  font-size:      8px;\n  color:          var(--color-text-dim);\n  text-align:     center;\n  letter-spacing: .04em;\n  line-height:    1.3;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  23  APP ICONS & FAVICONS\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.app-icon {\n  width:           72px;\n  height:          72px;\n  border-radius:   18px;   /* iOS/Android 22% corner radius */\n  display:         flex;\n  align-items:     center;\n  justify-content: center;\n  flex-shrink:     0;\n}\n\n.icon-label {\n  font-family:    var(--font-mono);\n  font-size:      9px;\n  color:          var(--color-text-dim);\n  text-transform: uppercase;\n  letter-spacing: .08em;\n  text-align:     center;\n}\n\n/* Favicon cells */\n.fav-cell { display: flex; flex-direction: column; align-items: center; gap: 8px; }\n.fav-box {\n  background:    #111213;\n  border-radius: 4px;\n  display:       flex;\n  align-items:   center;\n  justify-content: center;\n  border:        1px solid #3C3C3C;\n}\n.fav-light-box {\n  background:    #F2F2EF;\n  border-radius: 4px;\n  display:       flex;\n  align-items:   center;\n  justify-content: center;\n  border:        1px solid #D0D0CC;\n}\n.favicon-row { display: flex; align-items: flex-end; gap: 20px; margin-bottom: 40px; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  24  FORM ELEMENTS\n * ═══════════════════════════════════════════════════════════════════════════ */\n\ninput[type=\"text\"],\ninput[type=\"email\"],\ninput[type=\"password\"],\ninput[type=\"number\"],\ninput[type=\"search\"],\ninput[type=\"url\"],\ntextarea,\nselect {\n  display:        block;\n  width:          100%;\n  height:         42px;\n  padding:        0 16px;\n  background:     var(--color-surface);\n  border:         1px solid var(--color-border);\n  border-radius:  var(--radius-md);\n  font-family:    var(--font-body);\n  font-size:      var(--text-base);\n  font-weight:    var(--weight-regular);\n  color:          var(--color-text);\n  outline:        none;\n  -webkit-appearance: none;\n  appearance:     none;\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-fast),\n    box-shadow   var(--transition-fast),\n    color        var(--transition-theme);\n}\ntextarea {\n  height:      auto;\n  min-height:  100px;\n  padding:     12px 16px;\n  resize:      vertical;\n  line-height: var(--leading-body);\n}\ninput::placeholder,\ntextarea::placeholder { color: var(--color-text-dim); }\n\n/* Generic focus — product files override this with their accent */\ninput:focus,\ntextarea:focus,\nselect:focus {\n  border-color: var(--color-text-muted);\n  box-shadow:   0 0 0 2px color-mix(in srgb, var(--color-text-muted) 18%, transparent);\n}\n\n.form-label {\n  display:        block;\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  color:          var(--color-text-dim);\n  margin-bottom:  var(--space-2);\n}\n.form-group  { margin-bottom: var(--space-5); }\n.form-hint   { font-family: var(--font-mono); font-size: 11px; color: var(--color-text-dim); margin-top: var(--space-1); }\n.form-error  { font-family: var(--font-mono); font-size: 11px; color: var(--color-danger); margin-top: var(--space-1); }\n.form-group--error input,\n.form-group--error textarea { border-color: var(--color-danger); }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  25  THEME TOGGLE\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.toggle-wrap {\n  display:     flex;\n  align-items: center;\n  gap:         10px;\n  padding:     0 18px;\n  border-left: 1px solid var(--color-border);\n  flex-shrink: 0;\n  transition:  border-color var(--transition-theme);\n}\n\n.toggle-name {\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  color:          var(--color-text-dim);\n  min-width:      38px;\n  transition:     color var(--transition-theme);\n}\n\n.toggle-btn {\n  position:      relative;\n  width:         52px;\n  height:        28px;\n  border-radius: var(--radius-full);\n  background:    var(--color-surface);\n  border:        1px solid var(--color-border);\n  cursor:        pointer;\n  flex-shrink:   0;\n  outline:       none;\n  transition:\n    background   var(--transition-base),\n    border-color var(--transition-theme);\n}\n.toggle-btn::after {\n  content:       '';\n  position:      absolute;\n  top:           4px;\n  left:          4px;\n  width:         18px;\n  height:        18px;\n  border-radius: 50%;\n  background:    var(--color-text);\n  transition:\n    transform  var(--transition-spring),\n    background var(--transition-theme);\n}\n[data-theme=\"light\"] .toggle-btn::after { transform: translateX(24px); }\n\n/* Inline icon labels inside toggle */\n.ti          { position: absolute; font-size: 11px; top: 50%; transform: translateY(-50%); pointer-events: none; }\n.ti-m        { left: 7px; }\n.ti-s        { right: 6px; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  26  DO / DON'T GRID  (brand manual logo rules section)\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.do-dont-grid {\n  display:               grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap:                   12px;\n}\n\n.dont-cell {\n  border-radius: var(--radius-md);\n  overflow:      hidden;\n  border:        1px solid var(--color-border);\n  background:    var(--color-surface);\n}\n.dont-preview {\n  height:          110px;\n  background:      #111213;\n  display:         flex;\n  align-items:     center;\n  justify-content: center;\n  position:        relative;\n}\n.dont-preview.light-bg { background: #F2F2EF; }\n\n.dont-badge {\n  position:        absolute;\n  top:             10px;\n  right:           10px;\n  width:           22px;\n  height:          22px;\n  border-radius:   50%;\n  background:      #FF0050;\n  display:         flex;\n  align-items:     center;\n  justify-content: center;\n  font-size:       11px;\n  font-weight:     700;\n  color:           #fff;\n  flex-shrink:     0;\n}\n.do-badge { background: #25E673; color: #111213; }\n\n.dont-label         { padding: 12px 14px; }\n.dont-label p       { font-size: 12px; color: var(--color-text-muted); }\n.dont-label .dl-head {\n  font-family:    var(--font-mono);\n  font-size:      var(--text-label);\n  text-transform: uppercase;\n  letter-spacing: 0.10em;\n  color:          var(--color-text);\n  margin-bottom:  3px;\n}\n\n/* Clear space demo */\n.clearspace-demo { position: relative; display: inline-flex; align-items: center; justify-content: center; }\n.cs-box { position: absolute; inset: 0; border: 1.5px dashed rgba(27,207,224,.50); border-radius: 2px; pointer-events: none; }\n.cs-tick { position: absolute; font-family: var(--font-mono); font-size: 9px; color: #1BCFE0; white-space: nowrap; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  27  VOICE & TONE  (brand manual section 12)\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.voice-pillars {\n  display:               grid;\n  grid-template-columns: repeat(4, 1fr);\n  gap:                   12px;\n  margin-bottom:         40px;\n}\n\n.voice-pill-card {\n  border-radius: var(--radius-md);\n  border:        1px solid var(--color-border);\n  background:    var(--color-surface);\n  padding:       24px 20px;\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n.vpc-num {\n  font-family:    var(--font-mono);\n  font-size:      9px;\n  color:          var(--color-text-dim);\n  letter-spacing: var(--tracking-wide);\n  margin-bottom:  12px;\n  display:        block;\n}\n.vpc-h {\n  font-size:   var(--text-h5);\n  font-family: var(--font-display);\n  font-weight: var(--weight-regular);\n  color:       var(--color-text);\n  margin-bottom: 8px;\n}\n.vpc-p { font-size: 12px; color: var(--color-text-muted); line-height: 1.6; }\n\n.tone-matrix { width: 100%; border-collapse: collapse; margin-bottom: 40px; }\n.tone-matrix th {\n  font-family:    var(--font-mono);\n  font-size:      9px;\n  text-transform: uppercase;\n  letter-spacing: 0.12em;\n  color:          var(--color-text-dim);\n  padding:        10px 14px;\n  text-align:     left;\n  border-bottom:  1px solid var(--color-border);\n}\n.tone-matrix td {\n  padding:        14px 14px;\n  border-bottom:  1px solid color-mix(in srgb, var(--color-border) 50%, transparent);\n  font-size:      13px;\n  color:          var(--color-text-muted);\n  vertical-align: top;\n}\n.tone-matrix td:first-child { font-family: var(--font-mono); font-size: 11px; color: var(--color-text); font-weight: 500; white-space: nowrap; }\n.tone-matrix tr:last-child td { border-bottom: none; }\n\n.copy-example {\n  background:    var(--color-surface);\n  border:        1px solid var(--color-border);\n  border-radius: var(--radius-md);\n  padding:       24px 28px;\n  margin-bottom: 2px;\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n.ce-label { font-family: var(--font-mono); font-size: 9px; text-transform: uppercase; letter-spacing: 0.12em; color: var(--color-text-dim); display: block; margin-bottom: 10px; }\n.ce-bad   { font-size: 14px; color: #FF0050; text-decoration: line-through; margin-bottom: 8px; }\n.ce-good  { font-size: 14px; color: var(--color-text); font-weight: 500; }\n.ce-note  { font-size: 11px; color: var(--color-text-dim); margin-top: 6px; }\n\n.word-cols     { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 40px; }\n.word-list-box { border-radius: var(--radius-md); border: 1px solid var(--color-border); background: var(--color-surface); padding: 24px; }\n.wl-head       { display: flex; align-items: center; gap: 8px; margin-bottom: 16px; }\n.wl-dot        { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }\n.wl-dot-green  { background: #25E673; }\n.wl-dot-red    { background: #FF0050; }\n.wl-h          { font-family: var(--font-mono); font-size: var(--text-label); text-transform: uppercase; letter-spacing: 0.12em; color: var(--color-text); }\n.word-chip     { display: inline-flex; align-items: center; padding: 4px 10px; border-radius: 5px; font-size: 12px; margin: 3px; font-family: var(--font-mono); letter-spacing: .04em; }\n.chip-use      { background: color-mix(in srgb, #25E673 12%, transparent); border: 1px solid color-mix(in srgb, #25E673 30%, transparent); color: #25E673; }\n.chip-avoid    { background: color-mix(in srgb, #FF0050 12%, transparent); border: 1px solid color-mix(in srgb, #FF0050 30%, transparent); color: #FF0050; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  28  CO-BRANDING\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n.cobranding-rule {\n  display:       flex;\n  align-items:   flex-start;\n  gap:           14px;\n  padding:       16px 20px;\n  border-radius: 8px;\n  border:        1px solid var(--color-border);\n  margin-bottom: 8px;\n  background:    var(--color-surface);\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n.cbr-num  { font-family: var(--font-mono); font-size: var(--text-label); color: var(--color-text-dim); letter-spacing: 0.10em; width: 24px; flex-shrink: 0; padding-top: 2px; }\n.cbr-body h6 { font-size: 13px; letter-spacing: .04em; color: var(--color-text); margin-bottom: 3px; }\n.cbr-body p  { font-size: 13px; color: var(--color-text-muted); }\n\n.excl-zone   { position: relative; display: inline-flex; align-items: center; justify-content: center; }\n.excl-border { position: absolute; inset: -20px; border: 1.5px dashed rgba(255,0,80,.45); border-radius: 4px; pointer-events: none; }\n.excl-tick   { position: absolute; font-family: var(--font-mono); font-size: 8px; color: #FF0050; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  29  SVG HELPERS\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n/* Wordmark fill — adapts to active theme */\n.wm { fill: var(--color-text); transition: fill var(--transition-theme); }\n\n/* Decorative background grid (cover section) */\n.cover-grid {\n  position: absolute;\n  inset:    0;\n  pointer-events: none;\n  background-image:\n    linear-gradient(var(--color-grid-line) 1px, transparent 1px),\n    linear-gradient(90deg, var(--color-grid-line) 1px, transparent 1px);\n  background-size: 60px 60px;\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  30  FOOTER\n * ═══════════════════════════════════════════════════════════════════════════ */\n\nfooter {\n  padding:    var(--space-7) var(--space-7);\n  background: var(--color-bg);\n  border-top: 1px solid var(--color-border);\n  transition:\n    background   var(--transition-theme),\n    border-color var(--transition-theme);\n}\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  31  UTILITIES\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n/* Display */\n.flex          { display: flex; }\n.flex-col      { display: flex; flex-direction: column; }\n.flex-center   { display: flex; align-items: center; justify-content: center; }\n.flex-between  { display: flex; align-items: center; justify-content: space-between; }\n.flex-wrap     { flex-wrap: wrap; }\n.inline-flex   { display: inline-flex; }\n.hidden        { display: none; }\n\n/* Gap */\n.gap-1 { gap: var(--space-1); } .gap-2 { gap: var(--space-2); }\n.gap-3 { gap: var(--space-3); } .gap-4 { gap: var(--space-4); }\n.gap-5 { gap: var(--space-5); } .gap-6 { gap: var(--space-6); }\n\n/* Alignment */\n.items-center    { align-items: center; }\n.items-start     { align-items: flex-start; }\n.items-end       { align-items: flex-end; }\n.justify-center  { justify-content: center; }\n.justify-end     { justify-content: flex-end; }\n.justify-between { justify-content: space-between; }\n\n/* Text */\n.text-center  { text-align: center; }\n.text-right   { text-align: right; }\n.text-upper   { text-transform: uppercase; }\n.text-color   { color: var(--color-text); }\n.text-muted   { color: var(--color-text-muted); }\n.text-dim     { color: var(--color-text-dim); }\n\n/* Spacing */\n.mt-1{margin-top:var(--space-1)}.mt-2{margin-top:var(--space-2)}.mt-3{margin-top:var(--space-3)}\n.mt-4{margin-top:var(--space-4)}.mt-5{margin-top:var(--space-5)}.mt-6{margin-top:var(--space-6)}\n.mt-7{margin-top:var(--space-7)}.mt-8{margin-top:var(--space-8)}\n.mb-1{margin-bottom:var(--space-1)}.mb-2{margin-bottom:var(--space-2)}.mb-3{margin-bottom:var(--space-3)}\n.mb-4{margin-bottom:var(--space-4)}.mb-5{margin-bottom:var(--space-5)}.mb-6{margin-bottom:var(--space-6)}\n.mb-7{margin-bottom:var(--space-7)}.mb-8{margin-bottom:var(--space-8)}\n.p-4{padding:var(--space-4)}.p-5{padding:var(--space-5)}.p-6{padding:var(--space-6)}\n.px-4{padding-inline:var(--space-4)}.py-4{padding-block:var(--space-4)}\n.px-5{padding-inline:var(--space-5)}.py-5{padding-block:var(--space-5)}\n.px-6{padding-inline:var(--space-6)}.py-6{padding-block:var(--space-6)}\n\n/* Width */\n.w-full      { width: 100%; }\n.w-auto      { width: auto; }\n.flex-1      { flex: 1; }\n.flex-shrink-0 { flex-shrink: 0; }\n.min-w-0     { min-width: 0; }\n\n/* Border */\n.border   { border: 1px solid var(--color-border); }\n.border-t { border-top: 1px solid var(--color-border); }\n.border-b { border-bottom: 1px solid var(--color-border); }\n\n/* Overflow */\n.overflow-hidden { overflow: hidden; }\n.overflow-x-auto { overflow-x: auto; }\n.truncate        { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }\n\n\n/* ═══════════════════════════════════════════════════════════════════════════\n *  32  RESPONSIVE BREAKPOINTS\n * ═══════════════════════════════════════════════════════════════════════════ */\n\n@media (max-width: 1024px) {\n  :root { --text-h1: 36px; --text-h2: 30px; --text-h3: 22px; }\n  .page { padding-inline: var(--page-pad-md); }\n  .g2 { grid-template-columns: 1fr; }\n  section { padding: 64px 0; }\n  .voice-pillars { grid-template-columns: 1fr 1fr; }\n  .do-dont-grid  { grid-template-columns: 1fr 1fr; }\n}\n\n@media (max-width: 768px) {\n  :root { --text-h1: 28px; --text-h2: 24px; --text-h3: 20px; }\n  .page { padding-inline: var(--page-pad-sm); }\n  .g3  { grid-template-columns: 1fr; }\n  .logo-box { padding: 32px 24px; }\n  .mark-pair { grid-template-columns: 1fr 1fr; }\n  footer { padding: var(--space-6); }\n}\n\n@media (max-width: 480px) {\n  :root { --text-h1: 24px; --text-h2: 20px; --text-h3: 18px; --text-base: 15px; }\n  .g2, .g3, .g4 { grid-template-columns: 1fr; }\n  .mark-pair     { grid-template-columns: 1fr; }\n  .dl-row        { flex-direction: column; }\n  .dl-btn        { width: 100%; justify-content: center; }\n  .voice-pillars { grid-template-columns: 1fr; }\n  .do-dont-grid  { grid-template-columns: 1fr; }\n}\n\n/*\n * ═══════════════════════════════════════════════════════════════════════════\n *  END — shocknet-global.css  ·  v1.2\n * ═══════════════════════════════════════════════════════════════════════════\n */\n";

